import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"API Integration","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/api.md","filePath":"advanced/api.md"}'),i={name:"advanced/api.md"};function s(r,t,n,c,l,h){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="api-integration" tabindex="-1">API Integration <a class="header-anchor" href="#api-integration" aria-label="Permalink to &quot;API Integration&quot;">​</a></h1><p>Access your MyCompanyDesk data programmatically through the REST API.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>API access requires the <strong>Business</strong> plan.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The MyCompanyDesk API lets you:</p><ul><li>Create and retrieve invoices, expenses, and customers</li><li>Automate billing workflows</li><li>Integrate with other business tools</li><li>Build custom reporting</li><li>Sync data with external systems</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>All API requests require an API key sent in the request header:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer YOUR_API_KEY</span></span></code></pre></div><h3 id="creating-an-api-key" tabindex="-1">Creating an API key <a class="header-anchor" href="#creating-an-api-key" aria-label="Permalink to &quot;Creating an API key&quot;">​</a></h3><ol><li>Go to <strong>Settings &gt; API Keys</strong></li><li>Click <strong>Generate New Key</strong></li><li>Give the key a descriptive name</li><li>Copy the key — it&#39;s only shown once</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Store your API key securely. Never commit it to source control or share it publicly.</p></div><h2 id="base-url" tabindex="-1">Base URL <a class="header-anchor" href="#base-url" aria-label="Permalink to &quot;Base URL&quot;">​</a></h2><p>All API endpoints are available at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.mycompanydesk.com/api</span></span></code></pre></div><h2 id="key-endpoints" tabindex="-1">Key endpoints <a class="header-anchor" href="#key-endpoints" aria-label="Permalink to &quot;Key endpoints&quot;">​</a></h2><h3 id="customers" tabindex="-1">Customers <a class="header-anchor" href="#customers" aria-label="Permalink to &quot;Customers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/customers</code></td><td>List all customers</td></tr><tr><td><code>POST</code></td><td><code>/customers</code></td><td>Create a customer</td></tr><tr><td><code>GET</code></td><td><code>/customers/:id</code></td><td>Get a customer</td></tr><tr><td><code>PUT</code></td><td><code>/customers/:id</code></td><td>Update a customer</td></tr><tr><td><code>DELETE</code></td><td><code>/customers/:id</code></td><td>Delete a customer</td></tr></tbody></table><h3 id="invoices" tabindex="-1">Invoices <a class="header-anchor" href="#invoices" aria-label="Permalink to &quot;Invoices&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/invoices</code></td><td>List all invoices</td></tr><tr><td><code>POST</code></td><td><code>/invoices</code></td><td>Create an invoice</td></tr><tr><td><code>GET</code></td><td><code>/invoices/:id</code></td><td>Get an invoice</td></tr><tr><td><code>PUT</code></td><td><code>/invoices/:id</code></td><td>Update an invoice</td></tr><tr><td><code>DELETE</code></td><td><code>/invoices/:id</code></td><td>Delete an invoice</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/send</code></td><td>Send an invoice</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/mark-paid</code></td><td>Mark as paid</td></tr></tbody></table><h3 id="expenses" tabindex="-1">Expenses <a class="header-anchor" href="#expenses" aria-label="Permalink to &quot;Expenses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/expenses</code></td><td>List all expenses</td></tr><tr><td><code>POST</code></td><td><code>/expenses</code></td><td>Create an expense</td></tr><tr><td><code>GET</code></td><td><code>/expenses/:id</code></td><td>Get an expense</td></tr><tr><td><code>PUT</code></td><td><code>/expenses/:id</code></td><td>Update an expense</td></tr><tr><td><code>DELETE</code></td><td><code>/expenses/:id</code></td><td>Delete an expense</td></tr></tbody></table><h3 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/projects</code></td><td>List all projects</td></tr><tr><td><code>POST</code></td><td><code>/projects</code></td><td>Create a project</td></tr><tr><td><code>GET</code></td><td><code>/projects/:id</code></td><td>Get a project</td></tr><tr><td><code>PUT</code></td><td><code>/projects/:id</code></td><td>Update a project</td></tr></tbody></table><h3 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/search?q=term&amp;type=entity</code></td><td>Search across entities</td></tr></tbody></table><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><p>List endpoints support query parameters for filtering:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/invoices?status=sent&amp;customer_id=123&amp;limit=50</span></span></code></pre></div><p>Common filters:</p><ul><li><code>status</code> — Filter by status</li><li><code>customer_id</code> — Filter by customer</li><li><code>project_id</code> — Filter by project</li><li><code>limit</code> — Number of results (default: 50)</li><li><code>offset</code> — Pagination offset</li></ul><h2 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h2><p>API requests are rate-limited to ensure fair usage:</p><ul><li>Standard rate limit applies per API key</li><li>Exceeding the limit returns a <code>429 Too Many Requests</code> response</li><li>Include a retry strategy in your integration</li></ul><h2 id="error-handling" tabindex="-1">Error handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error handling&quot;">​</a></h2><p>The API returns standard HTTP status codes:</p><table tabindex="0"><thead><tr><th>Code</th><th>Description</th></tr></thead><tbody><tr><td><code>200</code></td><td>Success</td></tr><tr><td><code>201</code></td><td>Created</td></tr><tr><td><code>400</code></td><td>Bad request (check your parameters)</td></tr><tr><td><code>401</code></td><td>Unauthorized (invalid API key)</td></tr><tr><td><code>403</code></td><td>Forbidden (insufficient permissions)</td></tr><tr><td><code>404</code></td><td>Not found</td></tr><tr><td><code>429</code></td><td>Rate limited</td></tr><tr><td><code>500</code></td><td>Server error</td></tr></tbody></table><p>Error responses include a JSON body:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Description of what went wrong&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Configure webhooks to receive real-time notifications when events occur:</p><ul><li>Invoice sent</li><li>Invoice paid</li><li>Customer created</li><li>Expense added</li></ul><p>Set up webhooks in <strong>Settings &gt; API Keys &gt; Webhooks</strong>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use pagination for large datasets</li><li>Cache responses where appropriate to reduce API calls</li><li>Implement retry logic with exponential backoff for rate limits</li><li>Use webhooks instead of polling for real-time updates</li></ul>`,45)])])}const b=e(i,[["render",s]]);export{u as __pageData,b as default};
